+package github.chains;
+
+import spoon.Launcher;
+import spoon.processing.AbstractProcessor;
+import spoon.reflect.code.CtInvocation;
+import spoon.reflect.declaration.CtType;
+import spoon.reflect.factory.Factory;
+import spoon.reflect.reference.CtExecutableReference;
+import spoon.reflect.reference.CtTypeReference;
+import spoon.reflect.visitor.filter.TypeFilter;
+
+import java.util.Arrays;
+import java.util.List;
+
+public class Main {
+    private static final String SOURCE_DIRECTORY = argsOrDefault();
+
+    public static void main(String[] args) {
+        final String inputDirectory = args.length > 0 ? args[0] : SOURCE_DIRECTORY;
+
+        final Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.addInputResource(inputDirectory);
+        launcher.buildModel();
+
+        final Factory factory = launcher.getFactory();
+        final CtTypeReference<?> maxSizeConfig = factory.createCtTypeReference("com.hazelcast.config.MaxSizeConfig");
+        final CtTypeReference<?> evictionConfig = factory.createCtTypeReference("com.hazelcast.config.EvictionConfig");
+        final CtTypeReference<?> maxSizePolicy = factory.createCtTypeReference("com.hazelcast.config.MaxSizePolicy");
+        final CtTypeReference<?> uuidType = factory.createCtTypeReference("java.util.UUID");
+
+        launcher.getModel().getElements(new TypeFilter<>(CtInvocation.class)).forEach(invocation -> {
+            rewriteHazelcastInvocation(invocation, maxSizeConfig, evictionConfig, maxSizePolicy, uuidType, factory);
+        });
+
+        launcher.prettyprint();
+    }
+
+    private static String argsOrDefault() {
+        return ".";
+    }
+
+    private static void rewriteHazelcastInvocation(CtInvocation<?> invocation,
+                                                   CtTypeReference<?> maxSizeConfig,
+                                                   CtTypeReference<?> evictionConfig,
+                                                   CtTypeReference<?> maxSizePolicy,
+                                                   CtTypeReference<?> uuidType,
+                                                   Factory factory) {
+        final CtExecutableReference<?> executable = invocation.getExecutable();
+        if (executable == null) {
+            return;
+        }
+
+        final String declaring = executable.getDeclaringType() == null ? "" : executable.getDeclaringType().getQualifiedName();
+        final String name = executable.getSimpleName();
+
+        if ("addEntryListener".equals(name) && ("com.hazelcast.core.IMap".equals(declaring) || "com.hazelcast.map.IMap".equals(declaring) || declaring.endsWith(".IMap"))) {
+            if (invocation.getType() != null && "java.lang.String".equals(invocation.getType().getQualifiedName())) {
+                invocation.setType((CtTypeReference) uuidType.clone());
+            }
+            if (executable.getDeclaringType() != null) {
+                executable.getDeclaringType().setPackage(factory.createCtPackageReference("com.hazelcast.map"));
+            }
+            return;
+        }
+
+        if (invocation.getTarget() != null && "setMaxSizeConfig".equals(name) && invocation.getArguments().size() == 1) {
+            final CtTypeReference<?> targetType = invocation.getTarget().getType();
+            if (targetType != null && "com.hazelcast.config.MapConfig".equals(targetType.getQualifiedName())) {
+                final String argumentText = invocation.getArguments().get(0).toString();
+                if (argumentText.contains("MaxSizeConfig") && argumentText.contains("USED_HEAP_SIZE")) {
+                    final CtInvocation<?> newEviction = factory.createInvocation();
+                    newEviction.setTarget(invocation.getTarget());
+                    newEviction.setExecutable(factory.createExecutableReference());
+                    newEviction.getExecutable().setSimpleName("setEvictionConfig");
+                    newEviction.getExecutable().setDeclaringType((CtTypeReference) evictionConfig.clone());
+                    newEviction.addArgument(factory.createConstructorCall((CtTypeReference) evictionConfig.clone(), List.of()));
+                    final CtInvocation<?> evictionCtor = (CtInvocation<?>) newEviction.getArguments().get(0);
+
+                    final CtInvocation<?> setSize = factory.createInvocation();
+                    setSize.setTarget(evictionCtor);
+                    setSize.setExecutable(factory.createExecutableReference());
+                    setSize.getExecutable().setSimpleName("setSize");
+                    setSize.getExecutable().setDeclaringType((CtTypeReference) evictionConfig.clone());
+                    setSize.addArgument(invocation.getArguments().get(0).clone());
+
+                    final CtInvocation<?> setPolicy = factory.createInvocation();
+                    setPolicy.setTarget(setSize);
+                    setPolicy.setExecutable(factory.createExecutableReference());
+                    setPolicy.getExecutable().setSimpleName("setMaxSizePolicy");
+                    setPolicy.getExecutable().setDeclaringType((CtTypeReference) evictionConfig.clone());
+                    setPolicy.addArgument(factory.createCodeSnippetExpression("com.hazelcast.config.MaxSizePolicy.USED_HEAP_SIZE"));
+
+                    newEviction.clearArguments();
+                    newEviction.addArgument(setPolicy);
+                    invocation.replace(newEviction);
+                }
+            }
+        }
+    }
+}
